-- TailorBD Invoice System Migration
-- Run this script once against your TailorBDConnectionString database
-- ??????????????????????????????????????????????????????????????????????????????

-- 1. Add TotalAmount, PaidAmount, IsAutoGenerated columns to Invoice table
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Invoice' AND COLUMN_NAME='TotalAmount')
    ALTER TABLE Invoice ADD TotalAmount FLOAT NOT NULL DEFAULT 0;

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Invoice' AND COLUMN_NAME='PaidAmount')
    ALTER TABLE Invoice ADD PaidAmount FLOAT NOT NULL DEFAULT 0;

IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='Invoice' AND COLUMN_NAME='IsAutoGenerated')
    ALTER TABLE Invoice ADD IsAutoGenerated BIT NOT NULL DEFAULT 0;

-- 2. Backfill TotalAmount from Invoice_Line for existing rows (where TotalAmount = 0)
UPDATE Invoice
SET TotalAmount = ISNULL(
    (SELECT SUM(Amount) FROM Invoice_Line WHERE InvoiceID = Invoice.InvoiceID), 0
)
WHERE TotalAmount = 0;

-- 3. Backfill PaidAmount from Invoice_Payment_Record for existing rows (where PaidAmount = 0)
UPDATE Invoice
SET PaidAmount = ISNULL(
    (SELECT SUM(Amount) FROM Invoice_Payment_Record WHERE InvoiceID = Invoice.InvoiceID), 0
)
WHERE PaidAmount = 0;

-- 4. Fix PaymentStatus based on backfilled amounts
UPDATE Invoice
SET PaymentStatus =
    CASE
        WHEN PaidAmount >= TotalAmount AND TotalAmount > 0 THEN 'Paid'
        WHEN PaidAmount > 0 AND PaidAmount < TotalAmount   THEN 'Partial'
        ELSE 'Due'
    END
WHERE PaymentStatus IS NULL OR PaymentStatus = '';

-- 5. Create InvoiceAutoLog table for background service logging
IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME='InvoiceAutoLog')
BEGIN
    CREATE TABLE InvoiceAutoLog (
        LogID      INT IDENTITY(1,1) PRIMARY KEY,
        RunDate    DATETIME NOT NULL DEFAULT GETDATE(),
        Generated  INT NOT NULL DEFAULT 0,
        Skipped    INT NOT NULL DEFAULT 0,
        Errors     INT NOT NULL DEFAULT 0,
        Details    NVARCHAR(MAX) NULL
    );
END

-- 6. Summary
SELECT
    COUNT(*)                                                        AS TotalInvoices,
    SUM(CASE WHEN TotalAmount > 0 THEN 1 ELSE 0 END)               AS WithAmount,
    SUM(CASE WHEN PaidAmount  > 0 THEN 1 ELSE 0 END)               AS WithPayment,
    SUM(CASE WHEN PaymentStatus = 'Due'     THEN 1 ELSE 0 END)     AS DueCount,
    SUM(CASE WHEN PaymentStatus = 'Paid'    THEN 1 ELSE 0 END)     AS PaidCount,
    SUM(CASE WHEN PaymentStatus = 'Partial' THEN 1 ELSE 0 END)     AS PartialCount
FROM Invoice;

PRINT 'Migration complete.';
